import ComposableArchitecture
import Foundation

@Reducer
struct StatisticsFeature {
    @ObservableState
    struct State: Equatable {
        var displayedMonth: Date = Date()
        var focusedDates: Set<DateComponents> = []
    }

    enum Action {
        case onLoaded
        case backButtonTapped
        case prevMonthTapped
        case nextMonthTapped
    }

    @Dependency(\.dismiss) var dismiss

    var body: some ReducerOf<Self> {
        Reduce<State, Action> { state, action in
            switch action {
            case .onLoaded:
                return .none

            case .backButtonTapped:
                return .run { _ in
                    await self.dismiss()
                }

            case .prevMonthTapped:
                if let prev = Calendar.current.date(byAdding: .month, value: -1, to: state.displayedMonth) {
                    state.displayedMonth = prev
                }
                return .none

            case .nextMonthTapped:
                let calendar = Calendar.current
                guard let next = calendar.date(byAdding: .month, value: 1, to: state.displayedMonth),
                      let nextMonth = calendar.date(byAdding: .month, value: 1, to: Date()) else {
                    return .none
                }
                let nextComponents = calendar.dateComponents([.year, .month], from: next)
                let limitComponents = calendar.dateComponents([.year, .month], from: nextMonth)
                if nextComponents.year! < limitComponents.year! ||
                   (nextComponents.year! == limitComponents.year! && nextComponents.month! <= limitComponents.month!) {
                    state.displayedMonth = next
                }
                return .none
            }
        }
    }
}

