import SwiftUI
import ComposableArchitecture

struct StatisticsView: View {
    @Perception.Bindable private var store: StoreOf<StatisticsFeature>

    init(store: StoreOf<StatisticsFeature>) {
        self.store = store
    }

    var body: some View {
        WithPerceptionTracking {
            VStack(spacing: 0) {
                NavigationTitleView(title: "통계") {
                    store.send(.backButtonTapped)
                }

                ScrollView {
                    VStack(spacing: 40) {
                        statisticsSectionView(title: "집중 시간") {
                            EmptyView()
                        }

                        statisticsSectionView(title: "휴식 시간") {
                            EmptyView()
                        }

                        statisticsSectionView(title: "집중 캘린더") {
                            calendarView
                        }

                        statisticsSectionView(title: "캐릭터 사용 빈도") {
                            EmptyView()
                        }
                    }
                    .padding(.horizontal, 20)
                    .padding(.vertical, 20)
                }
            }
            .navigationBarBackButtonHidden(true)
            .background(.coolGray25)
            .onLoad {
                store.send(.onLoaded)
            }
        }
    }
}

// MARK: - Section

private extension StatisticsView {
    func statisticsSectionView(title: String, @ViewBuilder content: () -> some View) -> some View {
        VStack(alignment: .leading, spacing: 40) {
            Text(title)
                .pretendardFont(weight: .semiBold600, size: 20)
                .kerning(0.5)
                .foregroundStyle(.coolGray900)
            content()
        }
        .padding(.vertical, 24)
        .padding(.horizontal, 16)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(.white)
        .cornerRadius(24)
    }
}

// MARK: - Calendar

private extension StatisticsView {
    var calendarView: some View {
        let columns = Array(repeating: GridItem(.flexible()), count: 7)
        let days = calendarDays(for: store.displayedMonth)
        let today = Calendar.current.dateComponents([.year, .month, .day], from: Date())
        let isNextDisabled = isNextMonthDisabled

        return VStack(spacing: 0) {
            // 월 헤더
            HStack {
                Button {
                    store.send(.prevMonthTapped)
                } label: {
                    Image(.imageArrowLeft)
                        .renderingMode(.template)
                        .foregroundStyle(.coolGray900)
                        .frame(width: 24, height: 24)
                        .padding(10)
                }

                Spacer()

                Text(monthTitle(for: store.displayedMonth))
                    .pretendardFont(weight: .semiBold600, size: 16)
                    .foregroundStyle(.coolGray900)

                Spacer()

                Button {
                    store.send(.nextMonthTapped)
                } label: {
                    Image(.imageArrowRight)
                        .renderingMode(.template)
                        .foregroundStyle(isNextDisabled ? .coolGray300 : .coolGray900)
                        .frame(width: 24, height: 24)
                        .padding(10)
                }
                .disabled(isNextDisabled)
            }
            .frame(height: 48)

            // 날짜 그리드
            LazyVGrid(columns: columns, spacing: 20) {
                ForEach(0..<days.count, id: \.self) { index in
                    let item = days[index]
                    if item.isCurrentMonth {
                        let components = dayComponents(day: item.day, month: store.displayedMonth)
                        let isToday = components == today

                        // TODO: [TEST] 실제 데이터로 교체 필요
                        let isStreak = item.day == 15  // 연속집중한 날 테스트 (15일)
                        let isFocused = item.day == 10 // 집중한 날 테스트 (10일)
                        let isMostFocused = item.day == 15 // 이달 가장 집중한 날 테스트 (15일)

                        ZStack {
                            if isStreak {
                                // 5. 연속집중한 날: orange500 배경
                                Circle().fill(Color.orange500)
                            } else if isFocused {
                                // 4. 집중한 날: yellow500 배경
                                Circle().fill(Color.yellow500)
                            } else if isToday {
                                // 3. 오늘: coolGray900 테두리 (두께 2, inset 1)
                                Circle().fill(Color.coolGray50)
                                Circle().strokeBorder(Color.coolGray900, lineWidth: 2)
                            } else {
                                // 2. 디폴트: coolGray50 배경
                                Circle().fill(Color.coolGray50)
                            }

                            Text("\(item.day)")
                                .pretendardFont(weight: .medium500, size: 14)
                                .foregroundStyle(isStreak || isFocused ? .white : .coolGray800)
                        }
                        .frame(width: 32, height: 32)
                        .frame(maxWidth: .infinity)
                        .overlay(alignment: .topTrailing) {
                            if isMostFocused {
                                Image(.iconCalendarFire)
                                    .resizable()
                                    .frame(width: 20, height: 20)
                                    .offset(x: 7, y: -7)
                            }
                        }
                    } else {
                        // 1. 이전달/다음달 날짜: coolGray200 텍스트, 배경 없음
                        Text("\(item.day)")
                            .pretendardFont(weight: .medium500, size: 14)
                            .foregroundStyle(.coolGray200)
                            .frame(width: 32, height: 32)
                            .frame(maxWidth: .infinity)
                    }
                }
            }
            .padding(.top, 24)

            // 범례
            calendarLegendView
                .padding(.top, 24)
        }
    }

    var isNextMonthDisabled: Bool {
        let calendar = Calendar.current
        guard let nextMonth = calendar.date(byAdding: .month, value: 1, to: Date()) else { return false }
        let displayed = calendar.dateComponents([.year, .month], from: store.displayedMonth)
        let limit = calendar.dateComponents([.year, .month], from: nextMonth)
        return displayed.year == limit.year && displayed.month == limit.month
    }

    var calendarLegendView: some View {
        HStack(spacing: 16) {
            legendItem(indicator: { Circle().fill(Color.coolGray75).frame(width: 8, height: 8) }, label: "쉼")
            legendItem(indicator: { Circle().fill(Color.yellow500).frame(width: 8, height: 8) }, label: "집중")
            legendItem(indicator: { Circle().fill(Color.orange500).frame(width: 8, height: 8) }, label: "연속집중")
            legendItem(
                indicator: {
                    Image(.iconCalendarFire)
                        .resizable()
                        .frame(width: 11, height: 11)
                },
                label: "최고 집중"
            )
        }
        .frame(maxWidth: .infinity, alignment: .trailing)
    }

    func legendItem<Indicator: View>(indicator: () -> Indicator, label: String) -> some View {
        HStack(spacing: 4) {
            indicator()
            Text(label)
                .pretendardFont(weight: .medium500, size: 11)
                .foregroundStyle(.coolGray900)
        }
    }

    func monthTitle(for date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "ko_KR")
        formatter.dateFormat = "M월"
        return formatter.string(from: date)
    }

    func calendarDays(for month: Date) -> [(day: Int, isCurrentMonth: Bool)] {
        let calendar = Calendar.current
        guard
            let range = calendar.range(of: .day, in: .month, for: month),
            let firstDay = calendar.date(from: calendar.dateComponents([.year, .month], from: month))
        else { return [] }

        // 일요일 기준 첫 날의 요일 오프셋 (0=일, ..., 6=토)
        let weekday = calendar.component(.weekday, from: firstDay) - 1

        // 이전 달 날짜
        var items: [(day: Int, isCurrentMonth: Bool)] = []
        if weekday > 0, let prevMonth = calendar.date(byAdding: .month, value: -1, to: month),
           let prevRange = calendar.range(of: .day, in: .month, for: prevMonth) {
            let prevDays = Array((prevRange.upperBound - weekday)..<prevRange.upperBound)
            items += prevDays.map { (day: $0, isCurrentMonth: false) }
        }

        // 현재 달 날짜
        items += range.map { (day: $0, isCurrentMonth: true) }

        // 다음 달 날짜 (마지막 행 채우기)
        let remaining = (7 - items.count % 7) % 7
        if remaining > 0 {
            items += (1...remaining).map { (day: $0, isCurrentMonth: false) }
        }

        return items
    }

    func dayComponents(day: Int, month: Date) -> DateComponents {
        let calendar = Calendar.current
        var components = calendar.dateComponents([.year, .month], from: month)
        components.day = day
        return components
    }
}

