            Image(.imageTitleLogo)
                .resizable()
                .frame(width: Constants.logoWidth, height: Constants.logoHeight)

            Spacer()

            HStack(spacing: 8) {
                Image(.iconStatistics)
                    .resizable()
                    .frame(width: Constants.iconSize, height: Constants.iconSize)
                    .padding(.all, 14)
                    .background(Constants.iconBackgroundColor)
                    .cornerRadius(Constants.iconCornerRadius)
                    .onTapGesture {
                        onStatisticsButtonTapped?()
                    }

                Image(.iconSetting)
                    .resizable()
                    .frame(width: Constants.iconSize, height: Constants.iconSize)
                    .padding(.all, 14)
                    .background(Constants.iconBackgroundColor)
                    .cornerRadius(Constants.iconCornerRadius)
                    .onTapGesture {
                        onSettingButtonTapped?()
                    }
            }
        }
        .frame(maxWidth: .infinity)
        .padding(.horizontal, 20)
        .padding(.vertical, 8)
        .background(Constants.backgroundColor)
    }
}

